// Parse the Locations tab into per-location roster records. This sheet is a
// plain flat table (unlike the pricing_bd card dashboard) — verified against a
// real usedRange() pull 2026-07-07, fixture kept at n8n/roster_raw_grid.json.
// Layout: title row, a subtitle row, then a header row ("Code"/"State"/
// "Location"/"Status"/"Sales"/"Local Staff (Support Tours)"/"National Facility
// Manager"), then one data row per location. Find the header by content (not a
// fixed row index) so an extra title/subtitle line added later doesn't break it.
// Only pa/manager-per-location is surfaced in the app per Justin's ask
// (2026-07-07) — code/status/sales are still captured since they're free, in
// case they're wanted later, but the Roster tab itself leads with Local Staff
// and National Facility Manager.

const grid = ($json.values) || [];
function clean(v) { return (v === null || v === undefined) ? '' : String(v).trim(); }

let headerIdx = -1;
for (let i = 0; i < grid.length; i++) {
  const row = grid[i] || [];
  if (clean(row[0]) === 'Code' && clean(row[2]) === 'Location') { headerIdx = i; break; }
}
if (headerIdx === -1) throw new Error('Could not find the Code/Location header row — sheet layout may have changed.');

const rows = [];
for (let i = headerIdx + 1; i < grid.length; i++) {
  const row = grid[i] || [];
  const code = clean(row[0]);
  if (!code) continue; // blank spacer row
  rows.push({
    _id: 'r' + code,
    code, state: clean(row[1]), location: clean(row[2]), status: clean(row[3]), sales: clean(row[4]),
    local_staff: clean(row[5]) || '—', facility_manager: clean(row[6]) || '—'
  });
}
if (!rows.length) throw new Error('Roster parse produced 0 rows — check the sheet layout.');

return [{ json: { rows, count: rows.length } }];

function fv(v) {
  if (v === null || v === undefined) return { nullValue: null };
  if (typeof v === 'number') return Number.isInteger(v) ? { integerValue: String(v) } : { doubleValue: v };
  if (typeof v === 'boolean') return { booleanValue: v };
  if (Array.isArray(v)) return { arrayValue: { values: v.map(fv) } };
  if (typeof v === 'object') { const fields = {}; for (const k in v) fields[k] = fv(v[k]); return { mapValue: { fields } }; }
  return { stringValue: String(v) };
}

const rows = $json.rows || [];
const arr = rows.map(r => fv(r));
const patchBody = { fields: {
  rows: { arrayValue: { values: arr } },
  updatedAt: { stringValue: new Date().toISOString() },
  source: { stringValue: 'n8n roster sync (workflow 19)' },
  count: { integerValue: String(rows.length) }
} };

return [{ json: { patchBody, count: rows.length } }];
